<?php
declare(strict_types=1);

session_start();
require_once __DIR__ . '/../../koneksi/db_connection.php';

if (isset($_GET['reset']) && $_GET['reset'] === '1') {
  $_SESSION = [];

  if (ini_get('session.use_cookies')) {
    $params = session_get_cookie_params();
    setcookie(
      session_name(),
      '',
      time() - 42000,
      $params['path'],
      $params['domain'],
      (bool) $params['secure'],
      (bool) $params['httponly']
    );
  }

  session_destroy();
  header('Location: login.php');
  exit;
}

if (isset($_SESSION['user_id'])) {
  header('Location: dashboard.php');
  exit;
}

$errorMessage = '';

if ($_SERVER['REQUEST_METHOD'] === 'POST') {
  $email = trim((string) ($_POST['email'] ?? ''));
  $password = (string) ($_POST['passwod'] ?? '');

  if ($email === '' || $password === '') {
    $errorMessage = 'Email dan password wajib diisi.';
  } else {
    $stmt = $conn->prepare('SELECT id, nama, email, passwod FROM user WHERE email = ? LIMIT 1');

    if ($stmt) {
      $stmt->bind_param('s', $email);
      $stmt->execute();
      $result = $stmt->get_result();
      $user = $result ? $result->fetch_assoc() : null;
      $stmt->close();

      $passwordMatches = false;
      if ($user) {
        $storedPassword = (string) $user['passwod'];
        $passwordMatches = password_verify($password, $storedPassword) || hash_equals($storedPassword, $password);
      }

      if ($user && $passwordMatches) {
        session_regenerate_id(true);
        $_SESSION['user_id'] = (int) $user['id'];
        $_SESSION['user_nama'] = (string) $user['nama'];
        $_SESSION['user_email'] = (string) $user['email'];

        header('Location: dashboard.php');
        exit;
      }

      $errorMessage = 'Email atau password salah.';
    } else {
      $errorMessage = 'Terjadi masalah pada server. Coba lagi.';
    }
  }
}
